class Solution {
public:
    string smallestNumber(string pattern) {
        int n = pattern.size();
        vector<int> num(n + 1);
        for (int i = 0; i <= n; i++) num[i] = i + 1;
        for (int i = 0; i < n; i++) {
            if (pattern[i] == 'D') {
                for (int j = i + 1; j <= n; j++) {
                    if (num[j] > num[i]) {
                        swap(num[i], num[j]);
                        break;
                    }
                }
            }
        }
        for (int i = 0; i < n; i++) {
            if (pattern[i] == 'I') {
                for (int j = i + 1; j <= n; j++) {
                    if (num[j] < num[i]) {
                        swap(num[i], num[j]);
                        break;
                    }
                }
            }
        }
        string res;
        for (int i = 1; i <= n; i++) res += to_string(num[i]);
        return res;
    }
};
